import re

def detect_api_keys_in_autogen_messages(messages):
    patterns = [
        r'[ak|A-K][0-9a-zA-Z]{32,}',
        r'[sk-][0-9a-zA-Z]{48,}',
        r'AIza[0-9A-Za-z_]{35}',
        r'ghp_[0-9a-zA-Z]{36}'
    ]

    leaks = []
    for msg in messages:
        content = msg.get('content', '')
        for pattern in patterns:
            matches = re.findall(pattern, content)
            if matches:
                leaks.append({
                    'message_id': msg.get('message_id'),
                    'agent': msg.get('agent'),
                    'matches': matches,
                    'severity': 'CRITICAL'
                })
    return leaks

from autogen import register_function

def monitor_tool_registration(agent_roles, func_map):
    violations = []

    for agent_name, role in agent_roles.items():
        registered_tools = func_map.get(agent_name, [])
        allowed_tools = get_allowed_tools_for_role(role)

        unauthorized = [tool for tool in registered_tools 
                       if tool not in allowed_tools]

        if unauthorized:
            violations.append({
                'agent': agent_name,
                'role': role,
                'unauthorized_tools': unauthorized,
                'severity': 'HIGH'
            })
    return violations

def get_allowed_tools_for_role(role):
    role_permissions = {
        'researcher': ['search_web', 'read_docs'],
        'coder': ['execute_code', 'write_file'],
        'admin': ['*']
    }
    return role_permissions.get(role, [])

import ast

def detect_privilege_escalation(code):
    tree = ast.parse(code)
    escalations = []

    privilege_patterns = [
        'sudo', 'root', 'admin', 'elevate',
        'os.system.*bash', 'subprocess.*sudo',
        'open.*\/etc\/', 'open.*\/root\/'
    ]

    for node in ast.walk(tree):
        if isinstance(node, ast.Call):
            # Check function calls
            func_name = ast.unparse(node.func)
            for pattern in privilege_patterns:
                if re.search(pattern, func_name):
                    escalations.append({
                        'type': 'PRIV_ESC_CALL',
                        'function': func_name,
                        'line': node.lineno
                    })
    return escalations

