        'researcher': ['web_search'],
        'coder': ['safe_execute'],
        'reviewer': ['validate_code']
    }

    def secure_register_function(agent, functions: List[str]):
        role = agent.role
        allowed = role_permissions.get(role, [])

        for func_name in functions:
            if func_name not in allowed:
                print(f'⚠️  Blocked {agent.name}: {func_name} (not in {role} permissions)')
                continue

    agents = {
